+
+    #[test]
+    fn band_returns_correct_values() {
+        let ext = BreathingExtractor::new(1, 10.0, 30.0);
+        let (low, high) = ext.band();
+        assert!((low - 0.1).abs() < f64::EPSILON);
+        assert!((high - 0.5).abs() < f64::EPSILON);
