+        let conf = compute_confidence(&history);
+        assert!((conf - 0.0).abs() < f64::EPSILON);
+    }
+
+    #[test]
+    fn confidence_positive_for_oscillating_signal() {
+        let history: Vec<f64> = (0..100)
+            .map(|i| (i as f64 * 0.5).sin())
+            .collect();
+        let conf = compute_confidence(&history);
+        assert!(conf > 0.0);
