+
+    #[test]
+    fn generate_defaults_creates_templates() {
+        let mut matcher = FingerprintMatcher::new(4, 0.3);
+        matcher.generate_defaults(&[1.0, 2.0, 3.0, 4.0]);
+        assert_eq!(matcher.num_patterns(), 3); // Empty, Standing, Sitting
+    }
+}

