+
+    #[test]
+    fn static_signal_returns_deny_after_learning() {
+        let mut pipeline = WindowsWifiPipeline::with_config(PipelineConfig {
+            min_bssids: 1,
+            max_bssids: 4,
+            ..Default::default()
+        });
+        let frame = make_frame(4, &[-60.0, -65.0, -70.0, -75.0]);
